import React, { useState } from 'react';
import './TeamMatching.css';

function TeamMatching1() {
  const [selectedRole, setSelectedRole] = useState('');
  const [subRole, setSubRole] = useState('');
  const [keywords, setKeywords] = useState(['']);
  const [status, setStatus] = useState('waiting');

  const handleStartMatching = () => {
    setStatus('matching');
    setTimeout(() => setStatus('matched'), 3000); // 예시용 매칭 완료
  };

  return (
    <div className="team-page">
      <h2>AutoTeamUp - 빠르게 팀 결성하기</h2>
      <p className="description">공모전을 선택한 참가자들이 랜덤으로 팀을 결성한 후, 2차 피드백을 통해 최종 팀을 확정하는 방식입니다.</p>

      <div className="form-section">
        <label>희망 역할군</label>
        <input placeholder="예: 프론트엔드" value={selectedRole} onChange={(e) => setSelectedRole(e.target.value)} />

        <label>보조 가능 역할군</label>
        <input placeholder="예: 백엔드" value={subRole} onChange={(e) => setSubRole(e.target.value)} />

        <label>역량 키워드 (최대 2개)</label>
        <input
          placeholder="예: 빠른 커뮤니케이션"
          value={keywords[0]}
          onChange={(e) => setKeywords([e.target.value])}
        />

        <button className="cta-button" onClick={handleStartMatching}>팀업 신청하기</button>
      </div>

      {status === 'waiting' && <p className="status-msg">팀을 찾고 있습니다...</p>}
      {status === 'matched' && <p className="status-success">팀이 구성되었습니다! 확인해주세요.</p>}
    </div>
  );
}

export default TeamMatching1;
